      parameter (nxobs=256,nyobs=256)      character*48 dsname      character*48 postfl      character*8  ampunt      character*16 comp      character*21 title      character*5  tmsnp      dimension  u(nxobs,nyobs),v(nxobs,nyobs),upk(nxobs)      dimension  wu(nxobs),wv(nxobs),upk(nyobs),vpk(nyobs)**********  input  **************************************      title='h05sxm40z10  - 2.5D -'      dsname='/home/hales/tod/H/pseudo/MOVIE2.OUT'      postfl='/home/hales/tod/H/pseudo/postsn'      open(unit=10, file=dsname, ACCESS='SEQUENTIAL',     &       status='unknown', IOSTAT=IER )                  IF( IER.NE.0 ) THEN                                                         WRITE ( 6,* ) ' FILE(16) open ERR', IER                               STOP                                                                END IF      open(unit=2, file=postfl,     &     status='unknown')      comp='Horizontal Comp.'      tt=5.0      ampcm=1.0      xcmpkm=2.0      ycmpkm=2.0      xmin=-4.0      xmax= 4.0       dx=(xmax-xmin)/float(nxobs)      ymin=-4.0      ymax= 4.0       dy=(ymax-ymin)/float(nyobs)      xtck=1.0        ytck=1.0  c     ampind=0.5e-3*********************************************************      read(10,2100) time 2100 format(e10.3)      do 20 iy=1,nyobs         read(10,2400) (u(ix,iy),ix=1,nxobs)*         write(*,*) (u(ix,iy),ix=1,nxobs)   20 continue      do 40 iy=1,nyobs         read(10,2400) (v(ix,iy),ix=1,nxobs)   40 continue 2400 format(10e10.3)      close(unit=10)      do 80 iy=1,nyobs         do 60 ix=1,nxobs            wu(ix)=u(ix,iy)            wv(ix)=v(ix,iy)   60    continue         call  hlfamp(wu,1,nxobs,upk(iy))         call  hlfamp(wv,1,nxobs,vpk(iy))   80 continue         unrm=abs(upk(1))         vnrm=abs(vpk(1))         do 100 iy=1,nyobs            unrm=max(unrm,abs(upk(iy)))            vnrm=max(unrm,abs(vpk(iy)))  100 continue      uvnrm=max(unrm,vnrm)*     initialization for plotting      call  hplots( 1, 0, 2, 0 )*      x0=7.0      y0=3.0      x00=x0      y00=y0      call  plot(x0,y0,3)c     call  symbol(x0-ampcm-0.8,y0,0.4,dsname,90.0,26)      call  symbol(x0-3.5,y0,0.5,title,90.0,21)      call  symbol(x0-2.5,y0,0.5,comp,90.0,16)      call  symbol(x0-1.5,y0+4.0,0.5,'Time =',90.0,6)      call  symbol(x0-1.5,y0+6.5,0.5,tmsnp,90.0,5)      call  symbol(x0-1.5,y0+8.5,0.5,'(sec)',90.0,5)*     axis plotting      xln=(ymax-ymin)*ycmpkm+0.01      yln=(xmax-xmin)*xcmpkm+0.01      call  plot(x00,y00,3)      call  plot(x00+xln,y00,2)      call  plot(x00+xln,y00+yln,2)      call  plot(x00,y00+yln,2)      call  plot(x00,y00,2)      nxtck=(xmax-xmin)*1.01/xtck + 1      nytck=(ymax-ymin)*1.01/ytck + 1      do 200 i=1,nytck         ymark=x00+ytck*ycmpkm*(i-1)         call  plot(ymark,y00-0.3,3)         call  plot(ymark,y00,2)  200 continue      ynum=y00-0.8      do 300 i=1,nxtck,2         y=ymin+ytck*(i-1)         xnum=x00+ytck*ycmpkm*(i-1) - 0.6         call  number(xnum,ynum,0.4,y,0.0, 41)  300 continue      call  symbol(x00+xln*0.5-1.0,ynum-0.8,0.4,     &             'Y  (km)',0.0,7)      do 400 i=1,nytck         xmark=y00+xtck*xcmpkm*(i-1)         call  plot(x00+xln,xmark,3)         call  plot(x00+xln+0.3,xmark,2)  400 continue      xnum=x00+xln+0.8      do 500 i=1,nxtck,2         x=xmin+xtck*(i-1)         ynum=y00+xtck*xcmpkm*(i-1) - 0.6         call  number(xnum,ynum,0.4,x,90.0, 41)  500 continue      call  symbol(xnum+0.8,y00+yln*0.5-1.0,0.4,     &             'X  (km)',90.0,7)*     amp unit indicator      ampind=uvnrm      amp=ampind*ampcm/uvnrm      call  pen(-1,0)      call  plot(x00-1.0,y00+yln-amp,3)      call  plot(x00-1.0,y00+yln,2)      call  plot(x00-1.2,y00+yln-amp,3)      call  plot(x00-1.0,y00+yln-amp,2)      call  plot(x00-1.2,y00+yln,3)      call  plot(x00-1.0,y00+yln,2)      write(ampunt,'(1pe8.1)') ampind      call  symbol(x00-1.3,y00+yln-amp*0.5-1.0,0.4,ampunt,90.0,8)*     Plotting horizontal displacement      do 1000 iy=1,nyobs         do 1000 ix=1,nxobs            u(ix,iy)= u(ix,iy)/uvnrm * ampcm            v(ix,iy)= v(ix,iy)/uvnrm * ampcm 1000 continue      do 1200 iy=1,nyobs         x0=x00+dy*(iy-1)*ycmpkm         do 1100 ix=1,nxobs            y0=y00+dx*(ix-1)*xcmpkm            call  plot(x0,y0,3)            call  plot(x0+v(ix,iy),y0+u(ix,iy),2) 1100     continue 1200 continue      call  pen(6,0)      call  plot(x00,y00+2.0*xcmpkm,3)      call  plot(x00+yln,y00+2.0*xcmpkm,2)      call  plot(x00,y00+6.0*xcmpkm,3)      call  plot(x00+yln,y00+6.0*xcmpkm,2)      call  hplots( 0, 0, 2, 0)      close(unit=2)      stop      end*********************************************************      subroutine  maxmin(f,ns,ne,fmax,fmin)*     find maximum and minimum values of function f      dimension  f(ne)      fmax=0.0      fmin=0.0      do 100 i=ns,ne         if (f(i) .gt. fmax) fmax=f(i)         if (f(i) .lt. fmin) fmin=f(i)  100 continue      return      end**********************************************************      subroutine  hlfamp(f,ns,ne,fpeak)      dimension  f(ne)      call  maxmin(f,ns,ne,fmax,fmin)      if ( abs(fmax) .ge. abs(fmin) ) then         fpeak=fmax      else         fpeak=fmin      end if      write(6,*) 'fmax=',fmax,'fmin=',fmin,'fpeak=',fpeak      return      end**********************************************************      subroutine  seisg6(f,dt,nstart,nend,fpeak,fnrm,name,x0,y0,     &                   ptpamp,tseccm,ts,axtime,tckint,ampind,wx,wy)      character*8  name      character*8  fmm,ampunt      dimension  f(nend),wx(nend),wy(nend)*     scaling of amplitude      xscale=abs(ptpamp/fnrm)      write(fmm,'(1pe8.1)') fpeak*     scaling of time      write(6,*) 'dt=',dt,'nstart=',nstart,'nend=',nend,'fpeak=',fpeak      write(6,*) 'fnrm=',fnrm,'name=',name,'x0=',x0,'y0=',y0       write(6,*) 'ptpamp=',ptpamp,'tseccm=',tseccm,'dt=',dt,'ts=',ts      yscale=tseccm*dt      write(6,10) xscale, yscale   10 format(5x,'normalization factor',5x,'xscale=',1pe10.3,'(cm)',2x,     &       'yscale=',1pe10.3,'(cm)')*     x-y plotting of normalized seismograms      call  plot(x0+0.2,0.5,3)      call  symbol(x0+0.2,1.5,0.4,name,90.0,8)      do 100 i=nstart,nend         wx(i-nstart+1)=-xscale*f(i) + x0         wy(i-nstart+1)=yscale*(i-nstart) + y0  100 continue      call  plot(x0,y0,3)c     call  pen(-1,0)c     call  dashln(-1,0)      nn=nend-nstart+1      do 200 i=1,nn         call  plot(wx(i),wy(i),2)  200 continuec     call  pen(1,0)      write(fmm,'(1pe8.1)') fpeak      call  plot(x0+0.15,wy(nn)+1.0,3)      call  symbol(x0+0.15,wy(nn)+1.0,0.3,fmm,90.0,8)      return      end